import sys
from collections import defaultdict

def main():
    data = sys.stdin.buffer.read().split()
    ptr = 0
    n, m = int(data[ptr]), int(data[ptr+1]); ptr += 2

    x = [0]*(n+1)
    y = [0]*(n+1)
    for i in range(1, n+1):
        x[i], y[i] = int(data[ptr]), int(data[ptr+1]); ptr += 2

    active_trains = {}
    B = max(1, int(m**0.5))

    # For small mod: freq[(mod, xk)][r] = count of active trains with that mod,xk, and t%mod==r
    small_freq = defaultdict(lambda: defaultdict(int))
    large_active = {}  # model -> start_day, for large mod trains

    out = []

    for day in range(1, m+1):
        op, k = int(data[ptr]), int(data[ptr+1]); ptr += 2

        mod = x[k] + y[k]
        xk = x[k]

        if op == 1:
            active_trains[k] = day
            if mod <= B:
                small_freq[(mod, xk)][day % mod] += 1
            else:
                large_active[k] = day
        else:
            t = active_trains.pop(k)
            if mod <= B:
                small_freq[(mod, xk)][t % mod] -= 1
            else:
                del large_active[k]

        count = 0

        # Small mod contribution
        for (md, xk2), freq in small_freq.items():
            d_mod = day % md
            for r, cnt in freq.items():
                if cnt > 0:
                    diff = (d_mod - r) % md
                    if diff >= xk2:
                        count += cnt

        # Large mod contribution
        for model, start_day in large_active.items():
            md = x[model] + y[model]
            elapsed = day - start_day
            if elapsed % md >= x[model]:
                count += 1

        out.append(count)

    sys.stdout.write('\n'.join(map(str, out)) + '\n')

if __name__ == '__main__':
    main()

